const body = $input.item.json.body;
const productos = (body.productos || [])
  .map(p => `<li>${p.nombre} x${p.cantidad} — ${p.subtotal}€</li>`)
  .join('');
return [{json: {
  nombre: body.nombre,
  email: body.email,
  total: body.total,
  cart_id: body.cart_id,
  productos_html: `<ul>${productos}</ul>`
}}];
